import{_ as a,o as t,c as b,j as r,a as n,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"光明呼吸法","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/2.改造与功法/功法/光明呼吸法.md","filePath":"4.资源分区/2.改造与功法/功法/光明呼吸法.md"}'),o={name:"4.资源分区/2.改造与功法/功法/光明呼吸法.md"};function d(p,e,_,l,i,c){return t(),b("div",null,[...e[0]||(e[0]=[r("h1",{id:"光明呼吸法",tabindex:"-1"},[n("光明呼吸法 "),r("a",{class:"header-anchor",href:"#光明呼吸法","aria-label":'Permalink to "光明呼吸法"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风023元旦版")])])],-1),s('<h1 id="光明呼吸法-1" tabindex="-1">光明呼吸法 <a class="header-anchor" href="#光明呼吸法-1" aria-label="Permalink to &quot;光明呼吸法&quot;">​</a></h1><p>光明呼吸法<br> 描述：“光明是世间最伟大的力量之一，截取清晨第一缕光芒为己用，夺天地之造化，侵日月之玄机！”<br> 如果说常人的呼吸只在一吸一呼之间，那光明呼吸法就是通过特定的动作，节奏，导引，调和气血，潜移默化的改变身体。在修炼完成后会有一缕琉璃色的太阳光芒被牵引至修炼者体内，散入气血使全身灼热，修行者底蕴越强，太阳光芒就越粗，最终产生种种神异的效果。</p><p>呼吸法小成<br> 价格：D+600<br> 描述：呼吸法小成后，修炼者气血能够一次搬运一百零八周天，进入明劲层次。除了肉身力量得到强化外，反应与速度也得到了增强，即使是近距离被枪械偷袭也可以只靠危险感知横移，规避子弹。<br> 效果：你可以忽略最多不超过5点高速带来的影响；你需要每日清晨时花费一个小时进行吐纳导引，修行光明呼吸法，只要持之以恒的在影片内每日修行，则每场影片结束后可以在生理属性上获得1DP修行加值。</p><p>呼吸法小成（巅峰）<br> 价格：C+1200<br> 描述：在抵达小成巅峰后，呼吸产生的初阳之光已有中指粗细，能量高度集中，温度骇人。修行者需要忍耐灼热感将其炼化，运转气血凝练罡气，从而使自身力量进一步增长，身形之间越发灵活，拳脚力量进发之下隐隐产生灼烧他人的痕迹。<br> 效果：修炼至这一步，你将开启【罡气】能量池，这是一种介于内力与斗气的性质之间，由气血之力修炼出的能量循环。<br> ——<br> 【罡气】的关键属性是感知+耐力，恢复方式是通过十五分钟的短休息进行一次关键属性检定，恢复等同成功数的罡气。<br> 在一次长休息后，罡气也会自动恢复至满值，每日恢复的罡力不能超过上限的三倍。<br> 【罡气】的基础用法：<br> *自由动作启动，消耗3点罡气，你在生理属性上获得等同【传奇耐力】点增强加值，在触及距离上获得【传奇耐力】*2米的提升，持续一场景。<br> *自由动作启动，消耗3点罡气，你获得3点力场，持续一场景。<br> *只要使用过罡气的基础用法，在该场景内你的攻击伤害类型就可以转为火焰能量伤害。<br> ——<br> 现在你从D级中获取修行光明呼吸法的效果改为：你需要每日清晨时花费一个小时进行吐纳导引，修行光明呼吸法，只要持之以恒的在影片内每日修行，则每场影片结束后可以在生理属性上获得1DP修行加值，并扩大罡气能量池6点上限（保留已获得的成长DP，与能量池扩大的数值）。</p><p>呼吸法大成<br> 价格：B+2400<br> 描述：修炼至呼吸法大成后，初阳之光将直接融入骨骼，修炼者的精神得到同步强化，如水的精神力将像是水银一提坚韧，可以外放感知周围或观察自身的暗伤。精神的强大反哺肉身，是自身掌控能力大大加强，协调互补，进一步强化。<br> 效果：你获得了B级特异本质的侦测能力，具有【透视】特性。<br> 你在之前等级获得的基础用法得到了加强。<br> *自由动作启动，消耗5点罡气，你在生理属性上获得等同【传奇耐力】*2点增强加值，在触及距离上获得【传奇耐力】*5米的提升，持续一场景。<br> *自由动作启动，消耗5点罡气，你获得【传奇耐力】*2点力场防御，持续一场景。<br> *只要使用过罡气的基础用法，在该场景内你的攻击伤害类型就可以转为火焰能量伤害。<br> ——<br> 现在你从C级中获取修行光明呼吸法的效果改为：你需要每日清晨时花费一个小时进行吐纳导引，修行光明呼吸法，只要持之以恒的在影片内每日修行，则每场影片结束后可以在生理属性上获得1DP修行加值与等量附加成功，并扩大罡气能量池6点上限（保留已获得的成长DP加值）。</p><p>呼吸法大成（巅峰）<br> 价格：A+4800<br> 描述：修炼至巅峰后，修炼者躯体中的杂质会渐渐被排除，以后天返先天，浑身无垢，散发幽香，虽然强度变化幅度不大，但对自己身体的掌控能力将更上一层楼，一举一动之间皆可爆发出更强的力量层次。<br> 效果：现在你免疫A级疾病，毒素，创伤来源的效果。<br> 你在之前等级获得的基础用法得到了加强，现在你使用扩大扩大触及范围的用法时，将改为自身触及范围提升至自身敏感范围，这是罡气外放的表现。<br> 你在力量/敏捷相关检定上获得【8加骰】，这需要在购买时进行选择。同时每轮一次，你可以重骰一次以力量为关键属性进行的攻击，但必须接受重骰后的结果，使用这一能力时需要额外支付1点罡气。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',8)])])}const m=a(o,[["render",d]]);export{f as __pageData,m as default};
